wapAmount(uint256)":{"details":"Restricted to the governor. Delegates to {_setMaxWindowSwapAmount},      which checkpoints existing usage and emits {SetMaxWindowSwapAmount}.","params":{"maxWindowSwapAmount_":"New maximum SolvBTC amount that can be swapped in one window."}},"setWhitelistConfig(address,uint64,bool)":{"details":"Restricted to the governor. Delegates to {_setWhitelistConfig}.","params":{"account_":"Address to be whitelisted or updated.","expiration_":"Timestamp after which the whitelist entry becomes invalid.","isRateLimited_":"True if the account is subject to the global rate limit."}},"setWhitelistEnabled(bool)":{"details":"Restricted to the governor. Delegates to {_setWhitelistEnabled}.","params":{"isWhitelistEnabled_":"True to enforce whitelist, false to allow all callers."}},"swap(address,uint256,uint64)":{"details":"- If whitelist is enabled, the caller must have a valid, non-expired whitelist entry.   Rate limiting is then applied only to accounts flagged as rate-limited;    when whitelist is disabled, the same limits apply to all callers. - When an entry is rate-limited, this function:   - Enforces a per-transaction cap via `maxSingleSwapAmount`.   - Enforces a rolling-window cap via `maxWindowSwapAmount`,     using linear decay computed by {_amountCanBeSwapped}. - Transfers `solvbtcAmount_` of SolvBTC from the caller, burns it,    and pulls the corresponding amount of reserve currency from `currencyVault`. - Applies the configured fee rate and sends the fee portion to `feeRecipient`,    while the net amount is sent to `to_`. - Emits {SolvBTCSwapped} on success.","params":{"feeRate_":"The fee rate for each swap transaction.","solvbtcAmount_":"Amount of SolvBTC to swap, denominated in SolvBTC decimals.","to_":"Recipient address that will receive the reserve currency."},"returns":{"currencyAmount_":"Net amount of reserve currency sent to `to_` after fees are deducted."}},"whitelistConfig(address)":{"params":{"account_":"Address to query."},"return